import * as React from 'react';
import { render } from '@testing-library/react';
import { focus } from './focus';

const find = {
  get input() {
    return document.querySelector('input')!;
  },
};

describe('focus', () => {
  test('selectTextIfInput default value', () => {
    const wrapper = render(<input defaultValue="abc" />);
    expect(find.input.selectionStart).toBe(3);
    expect(find.input.selectionEnd).toBe(3);
    wrapper.unmount();
  });

  test('selectTextIfInput true', () => {
    const wrapper = render(<input defaultValue="abc" />);
    const input = wrapper.baseElement.querySelector('input');
    focus(input, {
      selectTextIfInput: true,
    });
    expect(find.input.selectionStart).toBe(0);
    expect(find.input.selectionEnd).toBe(3);
    wrapper.unmount();
  });
});
